import{_ as e,c as t,o as a,f as s}from"./chunks/framework.BOAZPCR7.js";const m=JSON.parse('{"title":"Influenza hemagglutinin subtypes have different sequence constraints despite sharing extremely similar structures","description":"","frontmatter":{"layout":"paper","title":"Influenza hemagglutinin subtypes have different sequence constraints despite sharing extremely similar structures","date":"2026-01-05","authors":["Jenny J Ahn","Timothy C Yu","Bernadeta Dadonaite","Caelan E Radford","Jesse D Bloom"],"journal":"bioRxiv","doi":"10.64898/2026.01.05.697808","link":"https://doi.org/10.64898/2026.01.05.697808","image":"/assets/papers/2026_ahn.jpg","keywords":["Influenza","Deep mutational scanning","Pseudovirus"],"selected":false,"head":[["link",{"rel":"canonical","href":"https://jbloomlab.org/papers/2026_ahn.html"}]]},"headers":[],"relativePath":"papers/2026_ahn.md","filePath":"papers/2026_ahn.md"}'),i={name:"papers/2026_ahn.md"},n=s('<h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Hemagglutinins (HA) from different influenza A virus subtypes share as little as ∼40% amino acid identity, yet their protein structure and cell entry function are highly conserved. Here we examine the extent that sequence constraints on HA differ across three subtypes. To do this, we first use pseudovirus deep mutational scanning to measure how all amino-acid mutations to an H7 HA affect its cell entry function. We then compare these new measurements to previously described measurements of how all mutations to H3 and H5 HAs affect cell entry function. We find that ∼50% of HA sites display substantially diverged preferences for different amino acids across the HA subtypes. The sites with the most divergent amino-acid preferences tend to be buried and have biochemically distinct wildtype amino acids in the different HA subtypes. We provide an example of how rewiring the interactions among contacting residues has dramatically shifted which amino acids are tolerated at specific sites. Overall, our results show how proteins with the same structure and function can become subject to very different site-specific evolutionary constraints as their sequences diverge.</p><h2 id="interactive-visualizations-and-computer-code" tabindex="-1">Interactive visualizations and computer code <a class="header-anchor" href="#interactive-visualizations-and-computer-code" aria-label="Permalink to &quot;Interactive visualizations and computer code&quot;">​</a></h2><ul><li><p>Effects of mutations to H7 HA: <a href="https://dms-vep.org/Flu_H7_Anhui13_DMS/" target="_blank" rel="noreferrer">https://dms-vep.org/Flu_H7_Anhui13_DMS/</a></p></li><li><p>Comparing mutation effects across HA subtypes: <a href="https://jbloomlab.github.io/ha-preference-shifts/" target="_blank" rel="noreferrer">https://jbloomlab.github.io/ha-preference-shifts/</a></p></li></ul>',4),r=[n];function o(c,l,u,d,h,p){return a(),t("div",null,r)}const _=e(i,[["render",o]]);export{m as __pageData,_ as default};
